```typescript
class FicheProduit {
    constructor(
        public nom: string,
        public prix: number,
        public description?: string,
        public photos?: string[],
        public avis?: string[],
        public disponibilite?: boolean,
        public livraison?: string
    ) {}
}

class FicheProduitBuilder {
    private nom!: string;
    private prix!: number;
    private description?: string;
    private photos: string[] = [];
    private avis: string[] = [];
    private disponibilite = true;
    private livraison = "standard";

    setNom(nom: string) { this.nom = nom; return this; }
    setPrix(prix: number) { this.prix = prix; return this; }
    setDescription(desc: string) { this.description = desc; return this; }
    ajouterPhoto(photo: string) { this.photos.push(photo); return this; }
    ajouterAvis(avis: string) { this.avis.push(avis); return this; }
    setDisponibilite(dispo: boolean) { this.disponibilite = dispo; return this; }
    setLivraison(livraison: string) { this.livraison = livraison; return this; }

    build(): FicheProduit {
        return new FicheProduit(
            this.nom, this.prix, this.description,
            this.photos, this.avis, this.disponibilite, this.livraison
        );
    }
}

// Utilisation
const fiche = new FicheProduitBuilder()
    .setNom("Ndolé")
    .setPrix(2500)
    .setDescription("Plat traditionnel")
    .ajouterPhoto("ndole.jpg")
    .build();
```
